order by id desc

select b.name as name, count(bo.id) as number from borrow bo left join book b on bo.book_no = b.book_no where 1=1
and bo.createtime > #{begin}
and bo.createtime < #{end}
and b.name is not null and b.name != '' group by b.name order by number desc limit 0,10

select bo.user_name as name, count(bo.id) as number from borrow bo where 1=1
and bo.createtime > #{begin}
and bo.createtime < #{end}
and bo.user_name is not null and bo.user_name != '' group by bo.user_name order by number desc limit 0,10

select b.category as name, count(bo.id) as number from borrow bo left join book b on bo.book_no = b.book_no where 1=1
and bo.createtime > #{begin}
and bo.createtime < #{end}
and b.category is not null and b.category != '' group by b.category order by number desc limit 0,10

SELECT * FROM borrow
WHERE user_no = #{userNo}

    AND status = #{status}

ORDER BY createtime DESC

SELECT * FROM borrow
WHERE user_no = #{userNo}
  AND book_no = #{bookNo}
  AND status IN ('待取书', '已借出')
ORDER BY id DESC
LIMIT 1
